// Minimal substring check for kernel (no libc)
static inline int k_str_contains(const char *s, const char *pat) {
    if (!s || !pat) return 0;
    if (*pat == '\0') return 1;
    for (const char *p = s; *p; p++) {
        const char *a = p;
        const char *b = pat;
        while (*a && *b && *a == *b) {
            a++;
            b++;
        }
        if (*b == '\0') return 1;
    }
    return 0;
}

