// Fetch the nth word-sized system call argument as a file descriptor
// and return both the descriptor and the corresponding struct file.
int argfd(int n, int *pfd, struct file **pf) {
    int fd;
    struct file *f;

    argint(n, &fd);
    if (fd < 0 || fd >= NOFILE || (f = myproc()->ofile[fd]) == 0) return -1;
    if (pfd) *pfd = fd;
    if (pf) *pf = f;
    return 0;
}

// Allocate toa file descripr for the given file.
// Takes over file reference from caller on success.
int fdalloc(struct file *f) {
    int fd;
    struct proc *p = myproc();

    for (fd = 0; fd < NOFILE; fd++) {
        if (p->ofile[fd] == 0) {
            p->ofile[fd] = f;
            return fd;
        }
    }
    return -1;
}

int fdalloc2(struct file *f, int start) {
    int fd;
    struct proc *p = myproc();

    for (fd = start; fd < NOFILE; fd++) {
        if (p->ofile[fd] == 0) {
            p->ofile[fd] = f;
            return fd;
        }
    }
    return -1;
}

uint64 sys_dup(void) {
    struct file *f;
    int fd;

    if (argfd(0, 0, &f) < 0) return -1;
    if ((fd = fdalloc(f)) < 0) return -1;
    get_fops()->dup(f);
    return fd;
}

uint64 sys_read(void) {
    struct file *f;
    int n;
    uint64 p;

    argaddr(1, &p);
    argint(2, &n);
    if (argfd(0, 0, &f) < 0) return -1;
    return get_fops()->read(f, p, n);
}

uint64 sys_pread64(void) {
    struct file *f;
    int n;
    uint64 p;
    uint64 offset;

    argaddr(1, &p);
    argint(2, &n);
    argaddr(3, &offset);
    if (argfd(0, 0, &f) < 0) return -1;

    // pread64 requires user address handling
    if (f->f_type == FD_REG) {
