uint64 sys_sleep(void) {
    int n;
    uint ticks0;

    argint(0, &n);
    // printf("sys_sleep acquire the tickslock\n");
    acquire(&tickslock);
    ticks0 = ticks;
    while (ticks - ticks0 < n) {
        if (myproc()->killed) {
            // printf("sys_sleep release the tickslock\n");
            release(&tickslock);
            return -1;
        }
        sleep(&ticks, &tickslock);
    }
    // printf("sys_sleep release the tickslock\n");
    release(&tickslock);
    return 0;
}

