// 内核环境不可用标准库，提供一个最小的子串匹配工具
static inline int k_str_contains(const char *s, const char *pat) {
    if (!s || !pat) return 0;
    if (*pat == '\0') return 1;
    for (const char *p = s; *p; p++) {
        const char *a = p;
        const char *b = pat;
        while (*a && *b && *a == *b) {
            a++;
            b++;
        }
        if (*b == '\0') return 1;
    }
    return 0;
}

