#define WriteReg(reg, v) (*(Reg(reg)) = (v))

// the transmit output buffer.
struct spinlock uart_tx_lock;
#define UART_TX_BUF_SIZE 32
char uart_tx_buf[UART_TX_BUF_SIZE];
uint64 uart_tx_w;  // write next to uart_tx_buf[uart_tx_w % UART_TX_BUF_SIZE]
uint64 uart_tx_r;  // read next from uart_tx_buf[uart_tx_r % UART_TX_BUF_SIZE]

extern volatile int panicked;  // from printf.c

void uartstart();

void uartinit(void) {
    // 对 VF2 / LA2K1000：不修改波特率相关设置，沿用 U-Boot 配置；清 FIFO，打开 RX 中断
#if defined(VF2) || (defined(LOONGARCH) && defined(LA2K1000))
    WriteReg(IER, 0x00);
    WriteReg(FCR, FCR_FIFO_ENABLE | FCR_FIFO_CLEAR);
    // Ensure IRQ output is enabled via OUT2, and assert RTS/DTR
    WriteReg(MCR, MCR_OUT2 | MCR_RTS | MCR_DTR);
    // Only enable RX interrupt to avoid THRE interrupt storms (output uses SBI)
    WriteReg(IER, IER_RX_ENABLE);
#else
    // Generic initialization for platforms with byte-spaced 16550.
    // disable interrupts.
    WriteReg(IER, 0x00);

    // special mode to set baud rate.
    WriteReg(LCR, LCR_BAUD_LATCH);

    // LSB for baud rate of 38.4K.
    WriteReg(0, 0x03);

    // MSB for baud rate of 38.4K.
    WriteReg(1, 0x00);

    // leave set-baud mode, and set word length to 8 bits, no parity.
    WriteReg(LCR, LCR_EIGHT_BITS);

    // reset and enable FIFOs.
    WriteReg(FCR, FCR_FIFO_ENABLE | FCR_FIFO_CLEAR);

    // enable transmit and receive interrupts.
    WriteReg(IER, IER_TX_ENABLE | IER_RX_ENABLE);
#endif

    initlock(&uart_tx_lock, "uart");
}

// add a character to the output buffer and tell the
// UART to start sending if it isn't already.
// blocks if the output buffer is full.
// because it may block, it can't be called
// from interrupts; it's only suitable for use
// by write().
void uartputc(int c) {
    acquire(&uart_tx_lock);

    if (panicked) {
        for (;;);
    }
    while (uart_tx_w == uart_tx_r + UART_TX_BUF_SIZE) {
        // buffer is full.
        // wait for uartstart() to open up space in the buffer.
        sleep(&uart_tx_r, &uart_tx_lock);
    }
    uart_tx_buf[uart_tx_w % UART_TX_BUF_SIZE] = c;
    uart_tx_w += 1;
    uartstart();
    release(&uart_tx_lock);
}

// alternate version of uartputc() that doesn't
// use interrupts, for use by kernel printf() and
// to echo characters. it spins waiting for the uart's
// output register to be empty.
void uartputc_sync(int c) {
    push_off();

    if (panicked) {
        for (;;);
    }

    // For LA2K1000, many terminal setups expect CRLF for a new line.
    // Insert a carriage return before line feed to ensure the cursor returns to column 0.
#if defined(LOONGARCH) && defined(LA2K1000)
    if (c == '\n') {
        while ((ReadReg(LSR) & LSR_TX_IDLE) == 0);
        WriteReg(THR, '\r');
    }
#endif

    // wait for Transmit Holding Empty to be set in LSR and send the character.
    while ((ReadReg(LSR) & LSR_TX_IDLE) == 0);
    WriteReg(THR, c);

    pop_off();
}

// if the UART is idle, and a character is waiting
// in the transmit buffer, send it.
// caller must hold uart_tx_lock.
// called from both the top- and bottom-half.
void uartstart() {
    while (1) {
        if (uart_tx_w == uart_tx_r) {
            // transmit buffer is empty.
            ReadReg(ISR);
            return;
        }

        if ((ReadReg(LSR) & LSR_TX_IDLE) == 0) {
            // the UART transmit holding register is full,
            // so we cannot give it another byte.
            // it will interrupt when it's ready for a new byte.
            return;
        }

        int c = uart_tx_buf[uart_tx_r % UART_TX_BUF_SIZE];
        uart_tx_r += 1;

        // maybe uartputc() is waiting for space in the buffer.
        wakeup(&uart_tx_r);

        WriteReg(THR, c);
    }
}

// read one input character from the UART.
// return -1 if none is waiting.
int uartgetc(void) {
    if (ReadReg(LSR) & 0x01) {
        // input data is ready.
        return ReadReg(RHR);
    } else {
        return -1;
    }
}

// handle a uart interrupt, raised because input has
// arrived, or the uart is ready for more output, or
// both. called from devintr().
void uartintr(void) {
#ifdef VF2
    // VF2: drain IIR sources to avoid THRE/LS/MDM storms
    while (1) {
        uint8 iir = ReadReg(ISR);
        if (iir & IIR_INT_PENDING) break;  // no pending
        uint8 iid = iir & IIR_ID_MASK;
        switch (iid) {
            case IIR_ID_RDA:
            case IIR_ID_RX_TIMEOUT:
                // read all available data
                while (ReadReg(LSR) & LSR_RX_READY) {
                    int ch = ReadReg(RHR);
                    consoleintr(ch);
                }
                break;
            case IIR_ID_THRE:
                // disable TX interrupt; we use polling-based uartstart
                WriteReg(IER, IER_RX_ENABLE);
                break;
            case IIR_ID_LS:
                (void)ReadReg(LSR);
                break;
            case IIR_ID_MODEM:
                (void)(*(Reg(MSR)));
                break;
            default:
                // defensive clear
                (void)ReadReg(LSR);
                while (ReadReg(LSR) & LSR_RX_READY) (void)ReadReg(RHR);
                break;
        }
    }
    acquire(&uart_tx_lock);
    uartstart();
    release(&uart_tx_lock);
#else
    // Generic path: read any pending rx and kick tx
    while (1) {
        int c = uartgetc();
        if (c == -1) break;
        consoleintr(c);
    }

    acquire(&uart_tx_lock);
    uartstart();
    release(&uart_tx_lock);
#endif
}

//
// driver for qemu's virtio disk device.
// uses qemu's mmio interface to virtio.
//
// qemu ... -drive file=fs.img,if=none,format=raw,id=x0 -device
// virtio-blk-device,drive=x0,bus=virtio-mmio-bus.0
//

#include "types.h"
#include "platform.h"
#include "defs.h"
#include "param.h"
#include "memlayout.h"
#include <lock/lock.h>
#include <fs/vfs/fs.h>
#include <fs/buf.h>
#include "dev/virtio.h"

// the address of virtio mmio register r.

#define R(r) ((volatile uint32 *)(VIRTIO0 + (r)))

static struct disk {
    // memory for virtio descriptors &c for queue 0.
    // this is a global instead of allocated because it must
    // be multiple contiguous pages, which kalloc()
    // doesn't support, and page aligned.
    char pages[2 * PGSIZE];
    struct VRingDesc *desc;
    uint16 *avail;
    struct UsedArea *used;

    // our own book-keeping.
    char free[NUM];   // is a descriptor free?
    uint16 used_idx;  // we've looked this far in used[2..NUM].

    // track info about in-flight operations,
    // for use when completion interrupt arrives.
    // indexed by first descriptor index of chain.
    struct {
        struct buf *b;
        char status;
    } info[NUM];

    struct spinlock vdisk_lock;

} __attribute__((aligned(PGSIZE))) disk;

void virtio_disk_init(void) {
    uint32 status = 0;

    initlock(&disk.vdisk_lock, "virtio_disk");

    if (*R(VIRTIO_MMIO_MAGIC_VALUE) != 0x74726976 || *R(VIRTIO_MMIO_VERSION) != 1 ||
        *R(VIRTIO_MMIO_DEVICE_ID) != 2 || *R(VIRTIO_MMIO_VENDOR_ID) != 0x554d4551) {
        panic("could not find virtio disk");
    }

    status |= VIRTIO_CONFIG_S_ACKNOWLEDGE;
    *R(VIRTIO_MMIO_STATUS) = status;

    status |= VIRTIO_CONFIG_S_DRIVER;
    *R(VIRTIO_MMIO_STATUS) = status;

    // negotiate features
    uint64 features = *R(VIRTIO_MMIO_DEVICE_FEATURES);
    features &= ~(1 << VIRTIO_BLK_F_RO);
    features &= ~(1 << VIRTIO_BLK_F_SCSI);
    features &= ~(1 << VIRTIO_BLK_F_CONFIG_WCE);
    features &= ~(1 << VIRTIO_BLK_F_MQ);
    features &= ~(1 << VIRTIO_F_ANY_LAYOUT);
    features &= ~(1 << VIRTIO_RING_F_EVENT_IDX);
    features &= ~(1 << VIRTIO_RING_F_INDIRECT_DESC);
    *R(VIRTIO_MMIO_DRIVER_FEATURES) = features;

    // tell device that feature negotiation is complete.
    status |= VIRTIO_CONFIG_S_FEATURES_OK;
    *R(VIRTIO_MMIO_STATUS) = status;

    // tell device we're completely ready.
    status |= VIRTIO_CONFIG_S_DRIVER_OK;
    *R(VIRTIO_MMIO_STATUS) = status;

    *R(VIRTIO_MMIO_GUEST_PAGE_SIZE) = PGSIZE;

    // initialize queue 0.
    *R(VIRTIO_MMIO_QUEUE_SEL) = 0;
    uint32 max = *R(VIRTIO_MMIO_QUEUE_NUM_MAX);
    if (max == 0) panic("virtio disk has no queue 0");
    if (max < NUM) panic("virtio disk max queue too short");
    *R(VIRTIO_MMIO_QUEUE_NUM) = NUM;
    memset(disk.pages, 0, sizeof(disk.pages));
    *R(VIRTIO_MMIO_QUEUE_PFN) = ((uint64)disk.pages) >> PGSHIFT;

    // desc = pages -- num * VRingDesc
    // avail = pages + 0x40 -- 2 * uint16, then num * uint16
    // used = pages + 4096 -- 2 * uint16, then num * vRingUsedElem

    disk.desc = (struct VRingDesc *)disk.pages;
    disk.avail = (uint16 *)(((char *)disk.desc) + NUM * sizeof(struct VRingDesc));
    disk.used = (struct UsedArea *)(disk.pages + PGSIZE);

    for (int i = 0; i < NUM; i++) disk.free[i] = 1;

// plic.c and trap.c arrange for interrupts from VIRTIO0_IRQ.
#ifdef DEBUG
    printf("virtio_disk_init\n");
#endif
}

// find a free descriptor, mark it non-free, return its index.
static int alloc_desc() {
    for (int i = 0; i < NUM; i++) {
        if (disk.free[i]) {
            disk.free[i] = 0;
            return i;
        }
    }
    return -1;
}

// mark a descriptor as free.
static void free_desc(int i) {
    if (i >= NUM) panic("virtio_disk_intr 1");
    if (disk.free[i]) panic("virtio_disk_intr 2");
    disk.desc[i].addr = 0;
    disk.desc[i].len = 0;
    disk.desc[i].flags = 0;
    disk.desc[i].next = 0;
    disk.free[i] = 1;
    wakeup(&disk.free[0]);
}

// free a chain of descriptors.
static void free_chain(int i) {
    while (1) {
        int flag = disk.desc[i].flags;
        int nxt = disk.desc[i].next;
        free_desc(i);
        if (flag & VRING_DESC_F_NEXT)
            i = nxt;
        else
            break;
    }
}

static int alloc3_desc(int *idx) {
    for (int i = 0; i < 3; i++) {
        idx[i] = alloc_desc();
        if (idx[i] < 0) {
            for (int j = 0; j < i; j++) free_desc(idx[j]);
            return -1;
        }
    }
    return 0;
}

void virtio_disk_rw(struct buf *b, int write) {
    // printf("[virtio_disk_rw] virtio disk rw, cpuid: %d\n", cpuid());
    uint64 sector = b->blockno;

    acquire(&disk.vdisk_lock);

    // the spec says that legacy block operations use three
    // descriptors: one for type/reserved/sector, one for
    // the data, one for a 1-byte status result.

    // allocate the three descriptors.
    int idx[3];
    while (1) {
        if (alloc3_desc(idx) == 0) {
            break;
        }
        sleep(&disk.free[0], &disk.vdisk_lock);
    }

    // format the three descriptors.
    // qemu's virtio-blk.c reads them.

    struct virtio_blk_outhdr {
        uint32 type;
        uint32 reserved;
        uint64 sector;
    } buf0;

    if (write)
        buf0.type = VIRTIO_BLK_T_OUT;  // write the disk
    else
        buf0.type = VIRTIO_BLK_T_IN;  // read the disk
    buf0.reserved = 0;
    buf0.sector = sector;

    // buf0 is on a kernel stack, which is not direct mapped,
    // thus the call to kvmpa().
    disk.desc[idx[0]].addr = (uint64)kwalkaddr((uint64)&buf0);
    // disk.desc[idx[0]].addr = (uint64) &buf0;
    disk.desc[idx[0]].len = sizeof(buf0);
    disk.desc[idx[0]].flags = VRING_DESC_F_NEXT;
    disk.desc[idx[0]].next = idx[1];

    disk.desc[idx[1]].addr = (uint64)b->data;
    disk.desc[idx[1]].len = BSIZE;
    if (write)
        disk.desc[idx[1]].flags = 0;  // device reads b->data
    else
        disk.desc[idx[1]].flags = VRING_DESC_F_WRITE;  // device writes b->data
    disk.desc[idx[1]].flags |= VRING_DESC_F_NEXT;
    disk.desc[idx[1]].next = idx[2];

    disk.info[idx[0]].status = 0;
    disk.desc[idx[2]].addr = (uint64)&disk.info[idx[0]].status;
    disk.desc[idx[2]].len = 1;
    disk.desc[idx[2]].flags = VRING_DESC_F_WRITE;  // device writes the status
    disk.desc[idx[2]].next = 0;

    // record struct buf for virtio_disk_intr().
    b->disk = 1;
    disk.info[idx[0]].b = b;

    // avail[0] is flags
    // avail[1] tells the device how far to look in avail[2...].
    // avail[2...] are desc[] indices the device should process.
    // we only tell device the first index in our chain of descriptors.
    disk.avail[2 + (disk.avail[1] % NUM)] = idx[0];
    __sync_synchronize();
    disk.avail[1] = disk.avail[1] + 1;

    *R(VIRTIO_MMIO_QUEUE_NOTIFY) = 0;  // value is queue number

    // Wait for virtio_disk_intr() to say request has finished.
    while (b->disk == 1) {
        sleep(b, &disk.vdisk_lock);
    }

    disk.info[idx[0]].b = 0;
    free_chain(idx[0]);

    release(&disk.vdisk_lock);
    // printf("[virtio_disk_rw] done, cpuid: %d\n", cpuid());
}

void virtio_disk_intr() {
    // printf("[virtio_disk_intr] virtio_disk_intr!\n");
    acquire(&disk.vdisk_lock);

    while ((disk.used_idx % NUM) != (disk.used->id % NUM)) {
        int id = disk.used->elems[disk.used_idx].id;

        if (disk.info[id].status != 0) panic("virtio_disk_intr status");

        disk.info[id].b->disk = 0;  // disk is done with buf
        wakeup(disk.info[id].b);

        disk.used_idx = (disk.used_idx + 1) % NUM;
    }
    *R(VIRTIO_MMIO_INTERRUPT_ACK) = *R(VIRTIO_MMIO_INTERRUPT_STATUS) & 0x3;

    release(&disk.vdisk_lock);
    // printf("[virtio_disk_intr] done!\n");
}

