#### 2.4.3 典型系统调用实现

**openat**：

```c
uint64 sys_openat(void) {
    int dirfd, flags, mode;
    char path[MAXPATH];

    argint(0, &dirfd);
    argstr(1, path, MAXPATH);
    argint(2, &flags);
    argint(3, &mode);

    // 构建绝对路径
    char absolute_path[MAXPATH];
    const char *base = (dirfd == AT_FDCWD) ? myproc()->cwd.path : myproc()->ofile[dirfd]->f_path;
    get_absolute_path(path, base, absolute_path);

    // 调用EXT4打开文件
    struct file *f = filealloc();
    int r = vfs_ext_open(absolute_path, flags, mode, f);

    // 分配文件描述符
    int fd = fdalloc(f);
    return fd;
}
```

**mmap**：

```c
uint64 sys_mmap(void) {
    uint64 addr, length, prot, flags, fd, offset;
    argaddr(0, &addr);
    argaddr(1, &length);
    argint(2, &prot);
    argint(3, &flags);
    argint(4, &fd);
    argaddr(5, &offset);

    struct proc *p = myproc();

    // 查找空闲VMA
    struct vma *v = NULL;
    for (int i = 0; i < NVMA; i++) {
        if (!p->vmas[i].valid) { v = &p->vmas[i]; break; }
    }
    if (!v) return -1;

    // 分配虚拟地址
    if (addr == 0) {
        addr = p->mmap_base;
        p->mmap_base -= PGROUNDUP(length);
    }

    // 记录VMA（延迟分配）
    v->addr = addr;
    v->length = length;
    v->prot = prot;
    v->flags = flags;
    v->f = (fd >= 0) ? p->ofile[fd] : NULL;
    v->offset = offset;
    v->valid = 1;

    return addr;
}
