int devintr() {
    uint64 scause = r_scause();

    if (scause == 0x8000000000000009L) {
        // 外部中断（PLIC）
        int irq = plic_claim();
        if (irq == UART0_IRQ) {
            uartintr();
            counter(UART0_IRQ);
        } else if (irq == VIRTIO0_IRQ) {
            virtio_disk_intr();
            counter(VIRTIO0_IRQ);
        }
        plic_complete(irq);
        return 1;
    } else if (scause == 0x8000000000000005L) {
        // 时钟中断
        clockintr();
        counter(CLOCK_IRQ);
        return 2;
    }
    return 0;
}
