            case VIRTIO_PCI_CAP_DEVICE_CFG:
                hw->device_cfg = get_cfg_addr(pci_base, &cap);
                break;
            case VIRTIO_PCI_CAP_NOTIFY_CFG:
                hw->notify_base = get_cfg_addr(pci_base, &cap);
                pci_config_read(&hw->notify_off_multiplier, 4, pos + sizeof(cap));
                break;
